```java
public void testOffsetWithInputOffset() throws Exception
{
    final JsonFactory f = new JsonFactory();
    JsonLocation loc;
    JsonParser p;
    // 3 spaces before, 2 after, just for padding
    byte[] b = "   { }  ".getBytes("UTF-8");

    // and then peel them off
    p = f.createParser(b, 3, b.length-5);  // "   { }  " with length 9, so 9-5=4, offset 3: takes indices 3,4,5,6 = "{ } "
    assertToken(JsonToken.START_OBJECT, p.nextToken());

    loc = p.getTokenLocation();
    assertEquals(0L, loc.getByteOffset());  // The offset of '{' token in subarray "{ } " is 0
    assertEquals(-1L, loc.getCharOffset());
    assertEquals(1, loc.getLineNr());
    assertEquals(1, loc.getColumnNr());

    loc = p.getCurrentLocation();
    assertEquals(1L, loc.getByteOffset());  // After consuming '{', cursor is at position 1 in subarray
    assertEquals(-1L, loc.getCharOffset());
    assertEquals(1, loc.getLineNr());
    assertEquals(2, loc.getColumnNr());

    p.close();
}
```

