index f89e661d..27b864e9 100644
--- a/src/main/java/com/fasterxml/jackson/core/json/UTF8StreamJsonParser.java
+++ b/src/main/java/com/fasterxml/jackson/core/json/UTF8StreamJsonParser.java
@@ -103,6 +103,13 @@ public class UTF8StreamJsonParser
      * buffer.
      */
     protected boolean _bufferRecyclable;
+
+    /**
+     * The initial offset used when the parser was created, needed to
+     * adjust location calculations to be relative to the effective start
+     * of the input rather than the original buffer start.
+     */
+    protected int _initialOffsetForLocation;

     /*
     /**********************************************************
@@ -123,6 +130,7 @@ public class UTF8StreamJsonParser
         _inputPtr = start;
         _inputEnd = end;
